# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
import os
import json

app = Flask(__name__)

# Directory to store images and their corresponding labels
IMAGE_DIR = 'images'
LABELS_FILE = 'labels.json'

# Ensure the directory exists
os.makedirs(IMAGE_DIR, exist_ok=True)

# Load existing labels if any
if os.path.exists(LABELS_FILE):
    with open(LABELS_FILE, 'r') as f:
        labels = json.load(f)
else:
    labels = {}

def majority_vote(label_list):
    from collections import Counter
    counter = Counter(label_list)
    most_common_label, _ = counter.most_common(1)[0]
    return most_common_label

@app.route('/annotate', methods=['POST'])
def annotate():
    image_id = request.form['image_id']
    label = request.form['label']

    if image_id not in labels:
        labels[image_id] = []

    labels[image_id].append(label)

    # Save the updated labels
    with open(LABELS_FILE, 'w') as f:
        json.dump(labels, f)

    return jsonify({"status": "success", "message": "Label submitted successfully"})

@app.route('/aggregate', methods=['GET'])
def aggregate():
    aggregated_labels = {}
    for image_id, label_list in labels.items():
        aggregated_labels[image_id] = majority_vote(label_list)

    return jsonify(aggregated_labels)

if __name__ == '__main__':
    app.run(debug=True)